class Solution:
    def minSwaps(self, s):
        n = len(s)
        ones = s.count('1')
        zeros = n - ones
        best = -1
        for start in (0, 1):
            want_ones = (n + 1) // 2 if start == 1 else n // 2
            if want_ones != ones:
                continue
            wrong = 0
            for i in range(n):
                expected = start ^ (i & 1)
                if int(s[i]) == 1 and expected == 0:
                    wrong += 1
            if best == -1 or wrong < best:
                best = wrong
        return best

