var minSwaps = function(s) {
    const n = s.length;
    let ones = 0;
    for (const c of s) if (c === '1') ones++;
    let best = -1;
    for (const start of [0, 1]) {
        const wantOnes = start === 1 ? Math.floor((n + 1) / 2) : Math.floor(n / 2);
        if (wantOnes !== ones) continue;
        let wrong = 0;
        for (let i = 0; i < n; i++) {
            const expected = start ^ (i & 1);
            if (+s[i] === 1 && expected === 0) wrong++;
        }
        if (best === -1 || wrong < best) best = wrong;
    }
    return best;
};
